import { Polyline } from "react-leaflet";

function getCurve(start, end) {
  const midLat = (start[0] + end[0]) / 2 + 2; // curve height
  const midLng = (start[1] + end[1]) / 2;

  return [
    start,
    [midLat, midLng],
    end,
  ];
}

export default function FlightPath() {
  const start = [12.9716, 77.5946];
  const end = [19.076, 72.8777];

  const curvedPath = getCurve(start, end);

  return (
    <Polyline
      positions={curvedPath}
      pathOptions={{
        color: "#00f7ff",
        weight: 4,
        opacity: 0.8,
      }}
    />
  );
}
